+    let token = value
+        .get("token")
+        .and_then(serde_json::Value::as_str)
+        .map(str::trim)
+        .filter(|value| !value.is_empty())?
+        .to_string();
+    let project_id = value
+        .get("projectId")
+        .or_else(|| value.get("project_id"))
+        .and_then(serde_json::Value::as_str)
+        .map(str::trim)
+        .filter(|value| !value.is_empty())
+        .unwrap_or("default-project")
+        .to_string();
+    Some((token, project_id))
